CREATE TABLE profiles (id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE, full_name TEXT, company_name TEXT NOT NULL, role TEXT NOT NULL CHECK (role IN ('producer','buyer','both')), phone TEXT, city TEXT, district TEXT, address TEXT, latitude DOUBLE PRECISION, longitude DOUBLE PRECISION, preferred_currency TEXT DEFAULT 'TRY' CHECK (preferred_currency IN ('TRY','USD','EUR')), preferred_language TEXT DEFAULT 'tr' CHECK (preferred_language IN ('tr','en')), total_co2_saved_kg NUMERIC DEFAULT 0, total_revenue_try NUMERIC DEFAULT 0, total_purchases_try NUMERIC DEFAULT 0, is_admin BOOLEAN DEFAULT FALSE, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE waste_categories (id SERIAL PRIMARY KEY, slug TEXT UNIQUE NOT NULL, name_tr TEXT NOT NULL, name_en TEXT NOT NULL, description_tr TEXT, description_en TEXT, default_emission_savings_kg_per_ton NUMERIC DEFAULT 0, icon TEXT);
CREATE TABLE listings (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), seller_id UUID REFERENCES profiles(id) ON DELETE CASCADE NOT NULL, title TEXT NOT NULL, description TEXT, category_id INTEGER REFERENCES waste_categories(id), ai_suggested_category_id INTEGER REFERENCES waste_categories(id), ai_confidence NUMERIC, quantity_value NUMERIC NOT NULL CHECK (quantity_value > 0), quantity_unit TEXT DEFAULT 'ton' CHECK (quantity_unit IN ('ton','kg','m3','piece')), price_try NUMERIC NOT NULL CHECK (price_try >= 0), is_negotiable BOOLEAN DEFAULT TRUE, is_export_eligible BOOLEAN DEFAULT FALSE, gtip_code TEXT, preferred_transport_mode TEXT DEFAULT 'road' CHECK (preferred_transport_mode IN ('road','rail','sea','air')), photo_urls TEXT[] DEFAULT ARRAY[]::TEXT[], pickup_latitude DOUBLE PRECISION NOT NULL, pickup_longitude DOUBLE PRECISION NOT NULL, pickup_address TEXT, pickup_city TEXT, status TEXT DEFAULT 'active' CHECK (status IN ('active','paused','sold','removed')), created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE INDEX listings_status_idx ON listings(status); CREATE INDEX listings_category_idx ON listings(category_id); CREATE INDEX listings_geo_idx ON listings(pickup_latitude,pickup_longitude);
CREATE TABLE transactions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), listing_id UUID REFERENCES listings(id) NOT NULL, seller_id UUID REFERENCES profiles(id) NOT NULL, buyer_id UUID REFERENCES profiles(id) NOT NULL, quantity NUMERIC NOT NULL CHECK (quantity > 0), price_try NUMERIC NOT NULL, total_try NUMERIC NOT NULL, distance_km NUMERIC, transport_mode TEXT CHECK (transport_mode IN ('road','rail','sea','air')), emission_factor_kg_per_ton_km NUMERIC, co2_kg NUMERIC, carbon_cost_try NUMERIC, usd_rate NUMERIC, eur_rate NUMERIC, rate_timestamp TIMESTAMPTZ, status TEXT DEFAULT 'pending' CHECK (status IN ('pending','approved','rejected','completed')), buyer_note TEXT, seller_note TEXT, created_at TIMESTAMPTZ DEFAULT NOW(), approved_at TIMESTAMPTZ, completed_at TIMESTAMPTZ);
CREATE TABLE exchange_rates (id SERIAL PRIMARY KEY, currency_pair TEXT NOT NULL, rate NUMERIC NOT NULL, source TEXT DEFAULT 'TCMB-EVDS', fetched_at TIMESTAMPTZ DEFAULT NOW()); CREATE INDEX exchange_rates_pair_idx ON exchange_rates(currency_pair,fetched_at DESC);
CREATE TABLE contact_requests (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), listing_id UUID REFERENCES listings(id) NOT NULL, buyer_id UUID REFERENCES profiles(id) NOT NULL, seller_id UUID REFERENCES profiles(id) NOT NULL, kvkk_accepted BOOLEAN DEFAULT FALSE NOT NULL, message TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE carbon_certificates (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), transaction_id UUID REFERENCES transactions(id) NOT NULL, user_id UUID REFERENCES profiles(id) NOT NULL, certificate_number TEXT UNIQUE NOT NULL, co2_saved_kg NUMERIC NOT NULL, pdf_url TEXT, issued_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE emission_factors (mode TEXT PRIMARY KEY, name_tr TEXT, name_en TEXT, factor_kg_co2_per_ton_km NUMERIC NOT NULL);
INSERT INTO emission_factors (mode,name_tr,name_en,factor_kg_co2_per_ton_km) VALUES ('air','Hava Kargo','Air Cargo',0.500),('sea','Deniz Yolu','Sea Freight',0.015),('road','Kara (TIR)','Road (Truck)',0.100),('rail','Demiryolu','Rail',0.030);
ALTER TABLE profiles ENABLE ROW LEVEL SECURITY; ALTER TABLE listings ENABLE ROW LEVEL SECURITY; ALTER TABLE transactions ENABLE ROW LEVEL SECURITY; ALTER TABLE contact_requests ENABLE ROW LEVEL SECURITY; ALTER TABLE carbon_certificates ENABLE ROW LEVEL SECURITY;
CREATE POLICY "profiles_select_all" ON profiles FOR SELECT USING (TRUE); CREATE POLICY "profiles_insert_own" ON profiles FOR INSERT WITH CHECK (auth.uid()=id); CREATE POLICY "profiles_update_own" ON profiles FOR UPDATE USING (auth.uid()=id);
CREATE POLICY "listings_select_active" ON listings FOR SELECT USING (status='active' OR seller_id=auth.uid()); CREATE POLICY "listings_insert_own" ON listings FOR INSERT WITH CHECK (auth.uid()=seller_id); CREATE POLICY "listings_update_own" ON listings FOR UPDATE USING (auth.uid()=seller_id); CREATE POLICY "listings_delete_own" ON listings FOR DELETE USING (auth.uid()=seller_id);
CREATE POLICY "tx_select_party" ON transactions FOR SELECT USING (auth.uid() IN (buyer_id,seller_id)); CREATE POLICY "tx_insert_buyer" ON transactions FOR INSERT WITH CHECK (auth.uid()=buyer_id); CREATE POLICY "tx_update_party" ON transactions FOR UPDATE USING (auth.uid() IN (buyer_id,seller_id));
CREATE POLICY "cr_insert_buyer" ON contact_requests FOR INSERT WITH CHECK (auth.uid()=buyer_id); CREATE POLICY "cr_select_party" ON contact_requests FOR SELECT USING (auth.uid() IN (buyer_id,seller_id)); CREATE POLICY "cc_select_own" ON carbon_certificates FOR SELECT USING (auth.uid()=user_id);
INSERT INTO storage.buckets (id,name,public) VALUES ('listing-photos','listing-photos',TRUE) ON CONFLICT DO NOTHING; CREATE POLICY "lp_select" ON storage.objects FOR SELECT USING (bucket_id='listing-photos'); CREATE POLICY "lp_insert" ON storage.objects FOR INSERT WITH CHECK (bucket_id='listing-photos' AND auth.role()='authenticated');
